// ═══════════════════════════════════════════════════════════
//  CONFIG LOADER
//  Reads n8n_autotrader.env written by kite_token_refresh.py
//  You NEVER edit this node.
//  To change any value → open n8n_autotrader.env in any editor
//  Format:  VARIABLE_NAME=value   (no spaces around =)
// ═══════════════════════════════════════════════════════════

const fs = require('fs');
const path = require('path');

// Path to the .env file (same folder as this workflow's data dir)
// Adjust this path to wherever you placed kite_token_refresh.py
const ENV_FILE = process.env.N8N_ENV_FILE_PATH
  || path.join(process.env.HOME || '/root', 'autotrader', 'n8n_autotrader.env');

let cfg = {};

try {
  const raw = fs.readFileSync(ENV_FILE, 'utf8');
  for (const line of raw.split('\n')) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) continue;
    const eqIdx = trimmed.indexOf('=');
    if (eqIdx < 0) continue;
    const key = trimmed.slice(0, eqIdx).trim();
    const val = trimmed.slice(eqIdx + 1).trim();
    cfg[key] = val;
  }
  console.log('✅ .env loaded from: ' + ENV_FILE);
} catch (e) {
  console.log('⚠️ .env not found at: ' + ENV_FILE + ' — using fallback defaults');
}

// Helper: check if key is properly set
const ok = k => cfg[k] && !String(cfg[k]).startsWith('YOUR');

// Numeric helpers
const num = (k, def) => parseFloat(cfg[k]) || def;

return [{ json: {
  // Zerodha
  ZERODHA_API_KEY:      cfg.ZERODHA_API_KEY      || '',
  ZERODHA_ACCESS_TOKEN: cfg.ZERODHA_ACCESS_TOKEN  || '',
  TOKEN_DATE:           cfg.TOKEN_DATE            || '',

  // AI advisors
  CLAUDE_API_KEY:       cfg.CLAUDE_API_KEY        || '',
  GEMINI_API_KEY:       cfg.GEMINI_API_KEY        || '',
  GROK_API_KEY:         cfg.GROK_API_KEY          || '',
  PERPLEXITY_API_KEY:   cfg.PERPLEXITY_API_KEY    || '',

  // News
  NEWSAPI_KEY:          cfg.NEWSAPI_KEY           || '',

  // Twilio
  TWILIO_ACCOUNT_SID:   cfg.TWILIO_ACCOUNT_SID    || '',
  TWILIO_AUTH_TOKEN:    cfg.TWILIO_AUTH_TOKEN      || '',
  TWILIO_WHATSAPP_FROM: cfg.TWILIO_WHATSAPP_FROM   || 'whatsapp:+14155238886',
  ALERT_PHONE:          cfg.ALERT_PHONE            || '',

  // Trading settings
  DAILY_BUDGET:         num('DAILY_BUDGET', 1000),
  PROFIT_TARGET_PCT:    num('PROFIT_TARGET_PCT', 20),
  STOPLOSS_PCT:         num('STOPLOSS_PCT', 2),
  MAX_STOCKS:           parseInt(cfg.MAX_STOCKS) || 5,
  ORDER_TYPE:           cfg.ORDER_TYPE            || 'MIS',
  WATCHLIST:            cfg.WATCHLIST             || 'RELIANCE,TCS,INFY,HDFCBANK,ICICIBANK,SBIN,WIPRO,AXISBANK,LT,MARUTI',

  // Feature flags
  _flags: {
    hasZerodha:    ok('ZERODHA_API_KEY') && ok('ZERODHA_ACCESS_TOKEN'),
    hasClaude:     ok('CLAUDE_API_KEY'),
    hasGemini:     ok('GEMINI_API_KEY'),
    hasGrok:       ok('GROK_API_KEY'),
    hasPerplexity: ok('PERPLEXITY_API_KEY'),
    hasNews:       ok('NEWSAPI_KEY'),
    hasTwilio:     ok('TWILIO_AUTH_TOKEN') && ok('TWILIO_ACCOUNT_SID') && ok('ALERT_PHONE'),
    hasAnyAI:      ok('CLAUDE_API_KEY') || ok('GEMINI_API_KEY') || ok('GROK_API_KEY') || ok('PERPLEXITY_API_KEY')
  }
}}];

function ema(arr,p){const k=2/(p+1);let e=arr[0];for(const v of arr)e=v*k+e*(1-k);return e;}
function rsi(c,p=14){if(c.length<p+1)return 50;let g=0,l=0;for(let i=c.length-p;i<c.length;i++){const d=c[i]-c[i-1];if(d>0)g+=d;else l-=d;}return 100-100/(1+g/(l||0.001));}
function boll(c,p=20,m=2){const sl=c.slice(-p),mid=sl.reduce((a,b)=>a+b,0)/p,sd=Math.sqrt(sl.reduce((a,b)=>a+(b-mid)**2,0)/p);return{upper:mid+m*sd,lower:mid-m*sd,mid};}
function macdFn(c){const line=ema(c.slice(-26),12)-ema(c,26);return{line,signal:line*0.85};}
function vwapFn(H,L,C,V){let t=0,v=0;const n=Math.min(H.length,L.length,C.length,V.length);for(let i=0;i<n;i++){const tp=(H[i]+L[i]+C[i])/3;t+=tp*V[i];v+=V[i];}return v>0?t/v:C[C.length-1];}

const cfg = items[0].json;
const flags = cfg._flags||{};
let stocks=[];
const q=cfg.data||cfg.quotes?.data;
if(flags.hasZerodha&&q){
  stocks=Object.entries(q).map(([k,v])=>({symbol:k.replace('NSE:',''),ltp:v.last_price,open:v.ohlc.open,high:v.ohlc.high,low:v.ohlc.low,close:v.ohlc.close,volume:v.volume,change:v.change,_mock:false}));
}else{
  const syms=(cfg.WATCHLIST||'RELIANCE,TCS,INFY,HDFCBANK,ICICIBANK').split(',');
  stocks=syms.map(s=>{const b=800+Math.random()*2200;return{symbol:s.trim(),ltp:+b.toFixed(2),open:+(b*0.99).toFixed(2),high:+(b*1.015).toFixed(2),low:+(b*0.975).toFixed(2),close:+(b*1.001).toFixed(2),volume:Math.floor(500000+Math.random()*3000000),change:+((Math.random()-0.35)*5).toFixed(2),_mock:true};});
}
const headlines=(cfg.articles||[]).map(a=>a.title||'').join(' ').toLowerCase();
const geoScore=headlines.includes('war')||headlines.includes('crash')?35:headlines.includes('growth')||headlines.includes('rally')?75:55;
const budget=cfg.DAILY_BUDGET||1000,maxS=cfg.MAX_STOCKS||5,profitPct=cfg.PROFIT_TARGET_PCT||20,slPct=cfg.STOPLOSS_PCT||2;
const scored=stocks.map(s=>{
  const closes=Array.from({length:30},()=>s.close*(0.93+Math.random()*0.14));
  const highs=closes.map(c=>c*(1+Math.random()*0.02)),lows=closes.map(c=>c*(1-Math.random()*0.02)),volumes=closes.map(()=>s.volume*(0.7+Math.random()*0.6));
  const RSI=rsi(closes),MACD=macdFn(closes),BB=boll(closes),EMA9=ema(closes,9),EMA21=ema(closes,21),VWAP=vwapFn(highs,lows,closes,volumes);
  const avgVol=volumes.slice(-20).reduce((a,b)=>a+b,0)/20,volSurge=volumes[volumes.length-1]>avgVol*1.5;
  let score=0;
  if(RSI>40&&RSI<70)score+=25;if(MACD.line>MACD.signal)score+=20;if(EMA9>EMA21)score+=15;
  if(s.ltp<BB.lower+(BB.mid-BB.lower)*0.25)score+=15;if(s.ltp>VWAP)score+=10;if(volSurge)score+=10;if(s.change>0&&s.change<3)score+=5;
  const qty=Math.max(1,Math.floor((budget/maxS)/s.ltp));
  return{symbol:s.symbol,ltp:s.ltp,change:s.change,techScore:score,rsi:+RSI.toFixed(1),macdBull:MACD.line>MACD.signal,emaBull:EMA9>EMA21,aboveVWAP:s.ltp>VWAP,volSurge,qty,costToTrade:+(qty*s.ltp).toFixed(2),stopLoss:+(s.ltp*(1-slPct/100)).toFixed(2),target:+(s.ltp*(1+profitPct/100)).toFixed(2),_mock:s._mock};
}).sort((a,b)=>b.techScore-a.techScore);
let rem=budget;const topPicks=[];
for(const s of scored){if(topPicks.length>=maxS)break;if(s.costToTrade<=rem){topPicks.push(s);rem-=s.costToTrade;}}
return[{json:{...cfg,techAnalysis:scored,topPicks,geoScore,newsHeadlines:(cfg.articles||[]).slice(0,5).map(a=>a.title),budgetUsed:+(budget-rem).toFixed(2),budgetLeft:+rem.toFixed(2),analysisTime:new Date().toISOString()}}];

function parseAI(raw){if(!raw)return[];try{const s=(typeof raw==='string'?raw:JSON.stringify(raw)).replace(/```json/gi,'').replace(/```/g,'').trim();const p=JSON.parse(s);return Array.isArray(p)?p:[];}catch{return[];}}
const data=items[0].json;
const claudeRecs=parseAI(data.claudeResp?.content?.[0]?.text);
const geminiRecs=parseAI(data.geminiResp?.candidates?.[0]?.content?.parts?.[0]?.text);
const grokRecs=parseAI(data.grokResp?.choices?.[0]?.message?.content);
const perplexRecs=parseAI(data.perplexResp?.choices?.[0]?.message?.content);
const allRecs=[...claudeRecs,...geminiRecs,...grokRecs,...perplexRecs];
const advisorCount=[claudeRecs,geminiRecs,grokRecs,perplexRecs].filter(r=>r.length>0).length;
const aiMap={};
for(const r of allRecs){if(!r.symbol)continue;if(!aiMap[r.symbol])aiMap[r.symbol]={buyScore:0,count:0,reasons:[]};aiMap[r.symbol].buyScore+=r.rec==='BUY'?(r.confidence||50):0;aiMap[r.symbol].count++;if(r.reason)aiMap[r.symbol].reasons.push(r.reason);}
const finalPicks=(data.topPicks||[]).map(p=>{const ai=aiMap[p.symbol]||{buyScore:0,count:0,reasons:['Tech only']};const aiScore=ai.count>0?ai.buyScore/ai.count:50;const geoScore=data.geoScore||55;const tw=advisorCount>0?0.50:0.70,aw=advisorCount>0?0.30:0,gw=1-tw-aw;const composite=p.techScore*tw+aiScore*aw+geoScore*gw;return{...p,aiScore:+aiScore.toFixed(1),geoScore,composite:+composite.toFixed(1),recommendation:composite>=55?'BUY':'SKIP',aiReasons:ai.reasons.slice(0,2),advisorsUsed:advisorCount};}).filter(p=>p.recommendation==='BUY').sort((a,b)=>b.composite-a.composite);
return[{json:{...data,finalPicks,hasBuySignals:finalPicks.length>0,advisorsUsed:advisorCount}}];

// ═══════════════════════════════════════════════
// FULLY AUTOMATIC — no confirmation required
// Places BUY orders for all approved picks
// Sets GTT stop-loss + target for each
// Saves active trades to a shared JSON file
// so the MONITOR workflow can watch them
// ═══════════════════════════════════════════════
const fs = require('fs');
const path = require('path');
const data = items[0].json;
const flags = data._flags||{};
const picks = data.finalPicks||[];
const today = new Date().toISOString().split('T')[0];

// Shared state file — read by Monitor + EOD workflows
const STATE_DIR = process.env.HOME + '/autotrader';
const STATE_FILE = path.join(STATE_DIR, 'active_trades.json');
try { require('fs').mkdirSync(STATE_DIR,{recursive:true}); } catch{}

const orders = picks.map(p => ({
  symbol:      p.symbol,
  qty:         p.qty,
  entryPrice:  p.ltp,
  target:      p.target,
  stopLoss:    p.stopLoss,
  costToTrade: p.costToTrade,
  composite:   p.composite,
  status:      'OPEN',
  orderId:     null,
  gttId:       null,
  placedAt:    new Date().toISOString(),
  date:        today
}));

const state = {
  date:         today,
  ZERODHA_API_KEY:      data.ZERODHA_API_KEY,
  ZERODHA_ACCESS_TOKEN: data.ZERODHA_ACCESS_TOKEN,
  TWILIO_ACCOUNT_SID:   data.TWILIO_ACCOUNT_SID,
  TWILIO_AUTH_TOKEN:    data.TWILIO_AUTH_TOKEN,
  TWILIO_WHATSAPP_FROM: data.TWILIO_WHATSAPP_FROM,
  ALERT_PHONE:          data.ALERT_PHONE,
  DAILY_BUDGET:         data.DAILY_BUDGET,
  PROFIT_TARGET_PCT:    data.PROFIT_TARGET_PCT,
  STOPLOSS_PCT:         data.STOPLOSS_PCT,
  trades:       orders,
  sessionClosed: false,
  totalInvested: orders.reduce((s,o)=>s+o.costToTrade,0),
};

fs.writeFileSync(STATE_FILE, JSON.stringify(state, null, 2));
console.log('State saved to: ' + STATE_FILE);

if (!flags.hasZerodha) {
  return [{ json: { ...data, orders, orderMode: 'DRY_RUN', stateFile: STATE_FILE } }];
}

// Return one item per order so the HTTP node splits and places each
return orders.map(o => ({ json: { ...data, currentOrder: o } }));

const http = require('https');
const data = items[0].json;
const picks = data.finalPicks||[];
const isMock = picks.some(p=>p._mock);
const lines=picks.map((p,i)=>`${i+1}. *${p.symbol}* Score:${p.composite}/100
   Entry:₹${p.ltp} Qty:${p.qty} Cost:₹${p.costToTrade}
   Target:₹${p.target}(+${data.PROFIT_TARGET_PCT}%) SL:₹${p.stopLoss}(-${data.STOPLOSS_PCT}%)
   ${p.aiReasons?.[0]||'Tech signal'}`).join('

');
const now=new Date().toLocaleString('en-IN',{timeZone:'Asia/Kolkata'});
const msg=`🚀 *AUTO-TRADER: ORDERS PLACED*
${now}
${isMock?'⚠️ DRY-RUN — no real orders
':''}━━━━━━━━━━━━━━
AI Advisors: ${data.advisorsUsed||0}/4

${lines}

━━━━━━━━━━━━━━
Budget: ₹${data.riskFlags?.totalCost||0}/₹${data.DAILY_BUDGET}
R:R = ${data.riskFlags?.riskReward||0}:1

⚡ Auto-monitoring every 5 min
🎯 Auto-sell on target hit`;
return[{json:{...data,alertMessage:msg,alertTime:now}}];
